import argparse
import json
import pickle
from pathlib import Path

import numpy as np
import torch
import torch.nn as nn
from torchvision import transforms, models
from transformers import AutoModel
from PIL import Image
from tqdm import tqdm
import timm

Image.MAX_IMAGE_PIXELS = None


class TestDataset(torch.utils.data.Dataset):
    def __init__(self, txt_path, img_root, transform):
        self.img_root = Path(img_root)
        self.transform = transform
        with open(txt_path, 'r') as f:
            self.samples = [line.strip() for line in f if line.strip()]

    def __len__(self):
        return len(self.samples)

    def __getitem__(self, idx):
        img = Image.open(self.img_root / self.samples[idx]).convert('RGB')
        return self.transform(img)


@torch.no_grad()
def extract_features(model, loader, device, is_vit=False):
    model.eval()
    feats = []
    for imgs in tqdm(loader, desc='Extract'):
        imgs = imgs.to(device)
        out = model(imgs)
        if is_vit and hasattr(out, 'last_hidden_state'):
            out = out.last_hidden_state[:, 0, :]
        # horizontal-flip TTA
        imgs_f = torch.flip(imgs, dims=[3])
        out_f = model(imgs_f)
        if is_vit and hasattr(out_f, 'last_hidden_state'):
            out_f = out_f.last_hidden_state[:, 0, :]
        avg = ((out + out_f) / 2.0).cpu().numpy()
        feats.append(avg)
    return np.concatenate(feats, axis=0)


def normalize(feats):
    return feats / (np.linalg.norm(feats, axis=1, keepdims=True) + 1e-8)


def predict_from_clf_list(clfs, X, bias=None):
    logits = np.mean([c.decision_function(X) for c in clfs], axis=0)
    if bias is not None:
        logits = logits + bias
    exp = np.exp(logits - np.max(logits, axis=1, keepdims=True))
    return exp / np.sum(exp, axis=1, keepdims=True)


def inspect_needs(obj, needs):
    if isinstance(obj, dict) and 'items' in obj:
        for item in obj['items']:
            inspect_needs(item, needs)
    elif isinstance(obj, dict) and 'clfs' in obj:
        inspect_needs(obj['clfs'], needs)
    elif isinstance(obj, list) and len(obj) > 0 and hasattr(obj[0], 'coef_'):
        dim = obj[0].coef_.shape[1]
        if dim == 768:
            needs['dino'] = True
        elif dim == 2048:
            needs['resnet'] = True
        elif dim == 2816:
            needs['dino'] = True
            needs['resnet'] = True
        elif dim == 3584:
            needs['dino'] = True
            needs['resnet'] = True
            needs['clip'] = True
    elif hasattr(obj, 'coef_'):
        dim = obj.coef_.shape[1]
        if dim == 768:
            needs['dino'] = True
        elif dim == 2048:
            needs['resnet'] = True
        elif dim == 2816:
            needs['dino'] = True
            needs['resnet'] = True
        elif dim == 3584:
            needs['dino'] = True
            needs['resnet'] = True
            needs['clip'] = True


def get_probs(obj, feats_d, feats_r, feats_c):
    if isinstance(obj, dict) and 'items' in obj:
        total = None
        for item in obj['items']:
            p = get_probs(item, feats_d, feats_r, feats_c) * item['weight']
            if total is None:
                total = p
            else:
                total += p
        return total
    elif isinstance(obj, dict) and 'clfs' in obj:
        dim = obj['clfs'][0].coef_.shape[1]
        if dim == 768:
            X = feats_d
        elif dim == 2048:
            X = feats_r
        elif dim == 2816:
            X = np.concatenate([feats_d, feats_r], axis=1)
        elif dim == 3584:
            X = np.concatenate([feats_d, feats_r, feats_c], axis=1)
        else:
            raise ValueError(f"Unknown feature dim {dim}")
        bias = obj.get('bias')
        return predict_from_clf_list(obj['clfs'], X, bias=bias)
    elif isinstance(obj, list) and len(obj) > 0 and hasattr(obj[0], 'coef_'):
        dim = obj[0].coef_.shape[1]
        if dim == 768:
            X = feats_d
        elif dim == 2048:
            X = feats_r
        elif dim == 2816:
            X = np.concatenate([feats_d, feats_r], axis=1)
        elif dim == 3584:
            X = np.concatenate([feats_d, feats_r, feats_c], axis=1)
        else:
            raise ValueError(f"Unknown feature dim {dim}")
        return predict_from_clf_list(obj, X, bias=None)
    elif hasattr(obj, 'coef_'):
        dim = obj.coef_.shape[1]
        if dim == 768:
            X = feats_d
        elif dim == 2048:
            X = feats_r
        elif dim == 2816:
            X = np.concatenate([feats_d, feats_r], axis=1)
        elif dim == 3584:
            X = np.concatenate([feats_d, feats_r, feats_c], axis=1)
        else:
            raise ValueError(f"Unknown feature dim {dim}")
        return obj.predict_proba(X)
    else:
        raise ValueError(f"Unsupported checkpoint format")


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', type=str, required=True)
    parser.add_argument('--checkpoint', type=str, required=True)
    parser.add_argument('--output', type=str, required=True)
    args = parser.parse_args()

    data_path = Path(args.data_path)
    img_root = data_path / 'images'
    test_txt = data_path / 'test.txt'
    ckpt_path = Path(args.checkpoint)

    device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')

    transform_dino = transforms.Compose([
        transforms.Resize(224, interpolation=transforms.InterpolationMode.BICUBIC),
        transforms.CenterCrop(224),
        transforms.ToTensor(),
        transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
    ])
    transform_resnet = transforms.Compose([
        transforms.Resize(224, interpolation=transforms.InterpolationMode.BICUBIC),
        transforms.CenterCrop(224),
        transforms.ToTensor(),
        transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225]),
    ])
    transform_clip = transforms.Compose([
        transforms.Resize(224, interpolation=transforms.InterpolationMode.BICUBIC),
        transforms.CenterCrop(224),
        transforms.ToTensor(),
        transforms.Normalize(mean=[0.48145466, 0.4578275, 0.40821073],
                             std=[0.26862954, 0.26130258, 0.27577711]),
    ])

    loader_kwargs = dict(batch_size=128, shuffle=False, num_workers=4, pin_memory=True)
    ds_d = TestDataset(test_txt, img_root, transform_dino)
    ds_r = TestDataset(test_txt, img_root, transform_resnet)
    ds_c = TestDataset(test_txt, img_root, transform_clip)
    loader_d = torch.utils.data.DataLoader(ds_d, **loader_kwargs)
    loader_r = torch.utils.data.DataLoader(ds_r, **loader_kwargs)
    loader_c = torch.utils.data.DataLoader(ds_c, **loader_kwargs)

    with open(ckpt_path, 'rb') as f:
        obj = pickle.load(f)

    needs = {'dino': False, 'resnet': False, 'clip': False}
    inspect_needs(obj, needs)

    feats_d = None
    feats_r = None
    feats_c = None

    if needs['dino']:
        dinov2 = AutoModel.from_pretrained('facebook/dinov2-base').to(device).eval()
        feats_d = normalize(extract_features(dinov2, loader_d, device, is_vit=True))
        del dinov2
        torch.cuda.empty_cache()

    if needs['resnet']:
        resnet = models.resnet50(weights=models.ResNet50_Weights.IMAGENET1K_V2)
        resnet.fc = nn.Identity()
        resnet = resnet.to(device).eval()
        feats_r = normalize(extract_features(resnet, loader_r, device, is_vit=False))
        del resnet
        torch.cuda.empty_cache()

    if needs['clip']:
        clip_model = timm.create_model('vit_base_patch16_clip_224.openai', pretrained=True, num_classes=0)
        clip_model = clip_model.to(device).eval()
        feats_c = normalize(extract_features(clip_model, loader_c, device, is_vit=False))
        del clip_model
        torch.cuda.empty_cache()

    probs = get_probs(obj, feats_d, feats_r, feats_c)
    preds = np.argmax(probs, axis=1).tolist()

    with open(args.output, 'w') as f:
        json.dump({'predictions': preds}, f)


if __name__ == '__main__':
    main()
